// Parse incoming alert payload from Flask
// Expected payload structure:
// {
//   student: 'Anshu',
//   student_email: 'student@example.com',
//   parent_email: 'parent@example.com',
//   alerts: [ {type:'marks', percentage:32.5}, {type:'attendance', percentage:28.0} ],
//   marks_percentage: 32.5,
//   attendance_percentage: 28.0,
//   threshold: 40,
//   triggered_at: '2026-03-09T10:30:00'
// }

const body = items[0].json.body || items[0].json;

const student            = body.student             || 'Unknown Student';
const student_email      = body.student_email       || '';
const parent_email       = body.parent_email        || '';
const alerts             = body.alerts              || [];
const marks_pct          = body.marks_percentage;
const attendance_pct     = body.attendance_percentage;
const threshold          = body.threshold           || 40;
const triggered_at       = body.triggered_at        || new Date().toISOString();

// Build alert summary text
const alertLines = alerts.map(a => {
  if (a.type === 'marks')      return `📉 Marks: ${a.percentage}% (below ${threshold}%)`;
  if (a.type === 'attendance') return `📅 Attendance: ${a.percentage}% (below ${threshold}%)`;
  return `⚠ ${a.type}: ${a.percentage}%`;
}).join('\n');

// Collect all recipients (filter empty)
const recipients = [student_email, parent_email].filter(e => e && e.includes('@'));

return recipients.map(email => ({
  json: {
    to: email,
    student,
    student_email,
    parent_email,
    alertLines,
    marks_pct,
    attendance_pct,
    threshold,
    triggered_at,
    alerts,
    is_parent: email === parent_email,
    recipient_type: email === parent_email ? 'Parent/Guardian' : 'Student'
  }
}));

