=<!DOCTYPE html>
<html>
<head>
  <meta charset='utf-8'>
  <style>
    body { font-family: 'Segoe UI', Arial, sans-serif; background: #f4f6f9; color: #1f2937; padding: 24px; }
    .card { max-width: 600px; margin: 0 auto; background: #fff; border-radius: 12px; overflow: hidden; box-shadow: 0 10px 30px rgba(0,0,0,0.1); }
    .header { background: linear-gradient(135deg, #dc2626, #f97316); color: #fff; padding: 28px 32px; }
    .header h1 { margin: 0 0 6px; font-size: 20px; }
    .header p  { margin: 0; opacity: 0.85; font-size: 13px; }
    .body { padding: 28px 32px; }
    .alert-box { background: #fff7ed; border-left: 4px solid #f97316; border-radius: 6px; padding: 14px 18px; margin: 16px 0; }
    .stat-row { display: flex; gap: 12px; margin: 20px 0; flex-wrap: wrap; }
    .stat { flex: 1; min-width: 120px; border-radius: 10px; padding: 14px; text-align: center; }
    .stat.bad  { background: #fef2f2; border: 1px solid #fca5a5; }
    .stat.ok   { background: #f0fdf4; border: 1px solid #86efac; }
    .stat .val { font-size: 24px; font-weight: 700; margin-bottom: 4px; }
    .stat.bad .val { color: #dc2626; }
    .stat.ok  .val { color: #16a34a; }
    .stat .lbl { font-size: 11px; color: #6b7280; text-transform: uppercase; letter-spacing: .05em; }
    .footer { text-align: center; padding: 16px; font-size: 12px; color: #9ca3af; border-top: 1px solid #e5e7eb; }
  </style>
</head>
<body>
<div class='card'>
  <div class='header'>
    <h1>⚠️ Low Performance Alert</h1>
    <p>AI Smart Attendance System – Automated Notification</p>
  </div>
  <div class='body'>
    <p>Dear <strong>{{ $json.recipient_type === 'Parent/Guardian' ? 'Parent/Guardian of ' + $json.student : $json.student }}</strong>,</p>
    <p>This is an automated alert. The following concern(s) have been detected:</p>
    <div class='alert-box'>
      <pre style='margin:0;font-family:inherit;white-space:pre-wrap;'>{{ $json.alertLines }}</pre>
    </div>
    <div class='stat-row'>
      {{ $json.marks_pct !== null ? `<div class='stat ${$json.marks_pct < $json.threshold ? 'bad' : 'ok'}'><div class='val'>${$json.marks_pct}%</div><div class='lbl'>Overall Marks</div></div>` : '' }}
      {{ $json.attendance_pct !== null ? `<div class='stat ${$json.attendance_pct < $json.threshold ? 'bad' : 'ok'}'><div class='val'>${$json.attendance_pct}%</div><div class='lbl'>Attendance Rate</div></div>` : '' }}
    </div>
    <p style='font-size:13px;color:#6b7280;'>Minimum required threshold: {{ $json.threshold }}% &bull; Checked at: {{ $json.triggered_at }}</p>
    <p>Please take immediate action to improve performance. Contact the institution for further support.</p>
  </div>
  <div class='footer'>AI Smart Attendance System &bull; Automated Notification &bull; Do not reply</div>
</div>
</body>
</html>
